# WebSocket server setup
def web_socket_server():
    addr = socket.getaddrinfo('0.0.0.0', 80)[0][-1]
    s = socket.socket()
    s.bind(addr)
    s.listen(5)

    while True:
        client, addr = s.accept()
        print("Connection from", addr)
        
        request = client.recv(1024)
        if b'Upgrade: websocket' in request:
            response = (
                'HTTP/1.1 101 Switching Protocols\r\n'
                'Upgrade: websocket\r\n'
                'Connection: Upgrade\r\n'
                'Sec-WebSocket-Accept: {accept}\r\n\r\n'
            ).format(accept="s3pPLMBiTxaQ9kYGzzhZRbK+xOo=")

            client.send(response)
            
            while True:
                data = client.recv(1024)
                if not data:
                    break
                
                opcode, payload = parse_websocket(data)
                if opcode == 1:  # Text frame
                    try:
                        command = json.loads(payload.decode('utf-8'))
                        handle_command(command)
                    except Exception as e:
                        print("Error parsing JSON:", e)

            client.close()

def parse_websocket(data):
    opcode = data[0] & 0x0F
    mask = (data[1] & 0x80) == 0x80
    payload_length = data[1] & 0x7F

    if payload_length == 126:
        payload_length = int.from_bytes(data[2:4], byteorder='big')
        offset = 4
    elif payload_length == 127:
        payload_length = int.from_bytes(data[2:10], byteorder='big')
        offset = 10
    else:
        offset = 2

    if mask:
        masking_key = data[offset:offset + 4]
        payload = bytearray([data[i] ^ masking_key[i % 4] for i in range(offset + 4, offset + 4 + payload_length)])
    else:
        payload = data[offset:offset + payload_length]

    return opcode, payload

def handle_command(command):
    if command.get("action") == "turn_on":
        led.value(1)
        print("LED turned on")
    elif command.get("action") == "turn_off":
        led.value(0)
        print("LED turned off")

# GPIO setup
led = Pin(2, Pin.OUT)

